    public static double totalCalories(List<? extends Fruit> fruits) {
        double total = 0;
        for (Fruit f : fruits) total += f.getCalories();
        // fruits.add(new Apple()); // COMPILE ERROR
        return total;
    }
    // CONSUMER Super: writes to dest
    public static void fillWithApples(List<? super Apple> basket, int count) {
        for (int i = 0; i < count; i++) basket.add(new Apple());
        // Apple a = basket.get(0); // COMPILE ERROR — only Object guaranteed
    }
    // Copy: src PRODUCES, dst CONSUMES
    public static <T> void copy(List<? extends T> src, List<? super T> dst) {
        for (T item : src) dst.add(item);
    }
    // Unbounded: only needs Object methods
    public static void printAll(List<?> items) {
        for (Object item : items) System.out.println(item);
    }
    public static void main(String[] args) {
        List<Apple> apples = Arrays.asList(new Apple(), new Apple());
        List<Banana> bananas = Arrays.asList(new Banana());
        System.out.println(totalCalories(apples));
        System.out.println(totalCalories(bananas));
