import java.util.*;
import java.util.function.*;

public class GenericStack<E> implements Iterable<E> {
    private Object[] elements;
    private int size = 0;

    @SuppressWarnings("unchecked")
    public GenericStack() { elements = new Object[16]; }

    public void push(E item) {
        if (size == elements.length) elements = Arrays.copyOf(elements, size * 2);
        elements[size++] = item;
    }

    @SuppressWarnings("unchecked")
    public E pop() {
        if (isEmpty()) throw new java.util.EmptyStackException();
        E item = (E) elements[--size];
        elements[size] = null;
        return item;
    }

    @SuppressWarnings("unchecked")
    public E peek() {
        if (isEmpty()) throw new java.util.EmptyStackException();
        return (E) elements[size - 1];
    }

    public boolean isEmpty() { return size == 0; }
    public int size() { return size; }

    public void pushAll(Iterable<? extends E> src) {
        for (E e : src) push(e);
    }

    public void popAll(Collection<? super E> dst) {
        while (!isEmpty()) dst.add(pop());
    }

    @SuppressWarnings("unchecked")
    public <R> GenericStack<R> map(Function<E, R> mapper) {
        GenericStack<R> result = new GenericStack<>();
        Object[] copy = Arrays.copyOf(elements, size);
        for (Object o : copy) result.push(mapper.apply((E) o));
        return result;
    }

    @Override
    @SuppressWarnings("unchecked")
    public Iterator<E> iterator() {
        return new Iterator<E>() {
            int cursor = size - 1;
            public boolean hasNext() { return cursor >= 0; }
            public E next() { return (E) elements[cursor--]; }
        };
    }

    public static void main(String[] args) {
        GenericStack<Integer> stack = new GenericStack<>();
        stack.pushAll(List.of(1, 2, 3, 4, 5));
        GenericStack<String> stringStack = stack.map(i -> "#" + i);
        List<Integer> list = new ArrayList<>();
        stack.popAll(list);
        System.out.println(list);
    }
}

