public class TypeErasureDemo {
    public static void erasureProof() {
        List<String> strings = new ArrayList<>();
        List<Integer> integers = new ArrayList<>();
        // At runtime both are just ArrayList!
        System.out.println(strings.getClass() == integers.getClass()); // true
        System.out.println(strings.getClass().getName()); // java.util.ArrayList
    }

    // Workaround 1: Class<T> token for instantiation
    public static <T> T createInstance(Class<T> clazz) throws Exception {
        return clazz.getDeclaredConstructor().newInstance();
    }

    // Workaround 2: Class<T> for instanceof equivalent
    public static <T> boolean isInstance(Object obj, Class<T> type) {
        return type.isInstance(obj);
    }

    // Heap pollution demo
    @SuppressWarnings({"unchecked", "rawtypes"})
    public static void heapPollution() {
        List rawList = new ArrayList();
        rawList.add("hello");
        rawList.add(42);
        List<String> strings = rawList; // unchecked warning
        // String s = strings.get(1);  // ClassCastException at RUNTIME
    }

    // Super type token — preserve generic type via anonymous subclass
    public static void reflectGenericType() {
        List<String> strings = new ArrayList<String>(){}; // anonymous subclass
        Type type = strings.getClass().getGenericSuperclass();
        System.out.println(type); // java.util.ArrayList<java.lang.String>
    }

    public static void main(String[] args) throws Exception {
        erasureProof();
        System.out.println(isInstance("hello", String.class));
        System.out.println(isInstance(42, String.class));
        reflectGenericType();
    }
}

import java.util.function.*;

public sealed interface Result<T, E> permits Result.Ok, Result.Err {
    record Ok<T, E>(T value) implements Result<T, E> {}
    record Err<T, E>(E error) implements Result<T, E> {}

    static <T, E> Result<T, E> ok(T value)  { return new Ok<>(value); }
    static <T, E> Result<T, E> err(E error) { return new Err<>(error); }

    default <U> Result<U, E> map(Function<T, U> mapper) {
        return switch (this) {
            case Ok<T,E> ok   -> Result.ok(mapper.apply(ok.value()));
            case Err<T,E> err -> Result.err(err.error());
        };
    }

    default <U> Result<U, E> flatMap(Function<T, Result<U, E>> mapper) {
        return switch (this) {
            case Ok<T,E> ok   -> mapper.apply(ok.value());
            case Err<T,E> err -> Result.err(err.error());
        };
    }

    default T getOrElse(T fallback) {
        return switch (this) {
            case Ok<T,E> ok   -> ok.value();
            case Err<T,E> err -> fallback;
        };
    }

    default boolean isOk() { return this instanceof Ok; }

    static Result<Integer, String> parsePositive(String s) {
        try {
            int n = Integer.parseInt(s);
            return n > 0 ? Result.ok(n) : Result.err("Must be positive: " + n);
        } catch (NumberFormatException e) {
            return Result.err("Not a number: " + s);
        }
    }

    static void main(String[] args) {
        Result<String, String> doubled = parsePositive("42")
            .map(n -> n * 2)
            .map(n -> "Result: " + n);
        System.out.println(doubled.getOrElse("failed")); // Result: 84
        System.out.println(parsePositive("abc").getOrElse("failed")); // failed
        Result<Integer, String> chained = parsePositive("10")
            .flatMap(n -> n > 5 ? Result.ok(n * 2) : Result.err("Too small"));
        System.out.println(chained.getOrElse(-1)); // 20
    }
}

