class Solution {
    public <T extends Comparable<T>> Pair<T,T> findMinMax(List<T> list) {
        if (list.isEmpty()) throw new IllegalArgumentException("Empty list");
        T min = list.get(0), max = list.get(0);
        for (T item : list) {
            if (item.compareTo(min) < 0) min = item;
            if (item.compareTo(max) > 0) max = item;
        }
        return new Pair<>(min, max);
    }
    public <T extends Comparable<T>> T findKth(List<T> list, int k) {
        if (k < 1 || k > list.size()) throw new IllegalArgumentException();
        List<T> copy = new ArrayList<>(list);
        Collections.sort(copy);
        return copy.get(k - 1);
    }
}

