class BST<T extends Comparable<T>> {
    private Node<T> root;
    private int size = 0;
    private static class Node<T> {
        T value; Node<T> left, right;
        Node(T v) { value = v; }
    }
    public void insert(T value) { root = insert(root, value); }
    private Node<T> insert(Node<T> node, T value) {
        if (node == null) { size++; return new Node<>(value); }
        int cmp = value.compareTo(node.value);
        if (cmp < 0) node.left  = insert(node.left, value);
        else if (cmp > 0) node.right = insert(node.right, value);
        return node;
    }
    public boolean contains(T value) {
        Node<T> cur = root;
        while (cur != null) {
            int cmp = value.compareTo(cur.value);
            if (cmp < 0) cur = cur.left;
            else if (cmp > 0) cur = cur.right;
            else return true;
        }
        return false;
    }
    public List<T> inorder() {
        List<T> result = new ArrayList<>();
        inorder(root, result);
        return result;
    }
    private void inorder(Node<T> node, List<T> result) {
        if (node == null) return;
        inorder(node.left, result);
        result.add(node.value);
        inorder(node.right, result);
    }
    public int size() { return size; }
}

