class Cache<K, V> {
    private static class Entry<V> {
        final V value;
        final long expiry;
        Entry(V v, long ttl) { value = v; expiry = System.currentTimeMillis() + ttl; }
        boolean isExpired() { return System.currentTimeMillis() >= expiry; }
    }
    private final Map<K, Entry<V>> store = new HashMap<>();
    private final long ttlMs;
    public Cache(long ttlMs) { this.ttlMs = ttlMs; }
    public void put(K key, V value) { store.put(key, new Entry<>(value, ttlMs)); }
    public Optional<V> get(K key) {
        Entry<V> entry = store.get(key);
        if (entry == null || entry.isExpired()) { store.remove(key); return Optional.empty(); }
        return Optional.of(entry.value);
    }
    public void evictExpired() { store.entrySet().removeIf(e -> e.getValue().isExpired()); }
    public int size() { evictExpired(); return store.size(); }
}

