class Graph<V, E> {
    private final Map<V, Map<V, E>> adjacency = new HashMap<>();
    public void addVertex(V v) { adjacency.putIfAbsent(v, new LinkedHashMap<>()); }
    public void addEdge(V from, V to, E weight) {
        if (!adjacency.containsKey(from)) throw new IllegalArgumentException("No vertex: " + from);
        if (!adjacency.containsKey(to))   throw new IllegalArgumentException("No vertex: " + to);
        adjacency.get(from).put(to, weight);
    }
    public Map<V, E> getNeighbors(V v) {
        return Collections.unmodifiableMap(adjacency.getOrDefault(v, Collections.emptyMap()));
    }
    public boolean hasVertex(V v) { return adjacency.containsKey(v); }
    public boolean hasEdge(V from, V to) {
        return adjacency.containsKey(from) && adjacency.get(from).containsKey(to);
    }
    public List<V> bfs(V start) {
        if (!adjacency.containsKey(start)) return Collections.emptyList();
        List<V> order = new ArrayList<>();
        Set<V> visited = new HashSet<>();
        Queue<V> queue = new LinkedList<>();
        queue.offer(start); visited.add(start);
        while (!queue.isEmpty()) {
            V curr = queue.poll();
            order.add(curr);
            for (V neighbor : adjacency.getOrDefault(curr, Collections.emptyMap()).keySet())
                if (visited.add(neighbor)) queue.offer(neighbor);
        }
        return order;
    }
}

