class NumberStats<T extends Number & Comparable<T>> {
    private final List<T> data;
    public NumberStats(List<T> data) {
        if (data.isEmpty()) throw new IllegalArgumentException();
        this.data = new ArrayList<>(data);
    }
    public double mean() {
        return data.stream().mapToDouble(Number::doubleValue).average().orElse(0);
    }
    public T max() { return Collections.max(data); }
    public T min() { return Collections.min(data); }
    public double median() {
        List<T> sorted = new ArrayList<>(data);
        Collections.sort(sorted);
        int n = sorted.size();
        return n % 2 == 1 ? sorted.get(n/2).doubleValue()
            : (sorted.get(n/2-1).doubleValue() + sorted.get(n/2).doubleValue()) / 2.0;
    }
    public double variance() {
        double mean = mean();
        return data.stream().mapToDouble(x -> { double d = x.doubleValue()-mean; return d*d; }).average().orElse(0);
    }
}

