class Pipeline<T> {
    private final T value;
    private final List<java.util.function.Function<T,T>> steps;
    private Pipeline(T value, List<java.util.function.Function<T,T>> steps) {
        this.value = value; this.steps = steps;
    }
    private Pipeline(T value) { this(value, new ArrayList<>()); }
    public static <T> Pipeline<T> start(T value) { return new Pipeline<>(value); }
    public Pipeline<T> then(java.util.function.Function<T,T> step) {
        steps.add(step); return this;
    }
    @SuppressWarnings("unchecked")
    public T execute() {
        Object result = value;
        for (var fn : steps) result = ((java.util.function.Function<Object,Object>)(Object)fn).apply(result);
        return (T) result;
    }
    public Optional<T> filter(java.util.function.Predicate<T> pred) {
        T result = execute();
        return pred.test(result) ? Optional.of(result) : Optional.empty();
    }
}

