class EventBus {
    private final Map<Class<?>, List<java.util.function.Consumer<?>>> handlers = new HashMap<>();
    public <T> void subscribe(Class<T> type, java.util.function.Consumer<T> handler) {
        handlers.computeIfAbsent(type, k -> new ArrayList<>()).add(handler);
    }
    public <T> void unsubscribe(Class<T> type, java.util.function.Consumer<T> handler) {
        List<java.util.function.Consumer<?>> list = handlers.get(type);
        if (list != null) list.remove(handler);
    }
    @SuppressWarnings("unchecked")
    public <T> void publish(T event) {
        List<java.util.function.Consumer<?>> list = handlers.get(event.getClass());
        if (list != null)
            for (java.util.function.Consumer<?> h : new ArrayList<>(list))
                ((java.util.function.Consumer<T>) h).accept(event);
    }
}

