class LRUCache<K, V> {
    private final int capacity;
    private final List<K> evictedKeys = new ArrayList<>();
    private final LinkedHashMap<K, V> cache;
    public LRUCache(int capacity) {
        this.capacity = capacity;
        this.cache = new LinkedHashMap<K, V>(capacity, 0.75f, true) {
            protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {
                boolean evict = size() > capacity;
                if (evict) evictedKeys.add(eldest.getKey());
                return evict;
            }
        };
    }
    public Optional<V> get(K key) { return Optional.ofNullable(cache.get(key)); }
    public void put(K key, V value) { cache.put(key, value); }
    public boolean containsKey(K key) { return cache.containsKey(key); }
    public int size() { return cache.size(); }
    public List<K> evictedKeys() { return Collections.unmodifiableList(evictedKeys); }
}

