public final class ImmutableList<T> implements Iterable<T> {
    private final Object[] data;
    private ImmutableList(Object[] data) { this.data = Arrays.copyOf(data, data.length); }
    @SafeVarargs
    public static <T> ImmutableList<T> of(T... items) { return new ImmutableList<>(items); }
    @SuppressWarnings("unchecked")
    public T get(int i) { return (T) data[i]; }
    public int size() { return data.length; }
    public boolean isEmpty() { return data.length == 0; }
    public boolean contains(T item) {
        for (Object o : data) if (Objects.equals(o, item)) return true;
        return false;
    }
    public ImmutableList<T> prepend(T item) {
        Object[] newData = new Object[data.length + 1];
        newData[0] = item;
        System.arraycopy(data, 0, newData, 1, data.length);
        return new ImmutableList<>(newData);
    }
    public ImmutableList<T> tail() {
        if (isEmpty()) throw new java.util.NoSuchElementException();
        return new ImmutableList<>(Arrays.copyOfRange(data, 1, data.length));
    }
    public ImmutableList<T> concat(ImmutableList<T> other) {
        Object[] combined = new Object[data.length + other.data.length];
        System.arraycopy(data, 0, combined, 0, data.length);
        System.arraycopy(other.data, 0, combined, data.length, other.data.length);
        return new ImmutableList<>(combined);
    }
    @SuppressWarnings("unchecked")
    public ImmutableList<T> filter(java.util.function.Predicate<T> pred) {
        List<Object> result = new ArrayList<>();
        for (Object o : data) if (pred.test((T)o)) result.add(o);
        return new ImmutableList<>(result.toArray());
    }
    @SuppressWarnings("unchecked")
    public <R> ImmutableList<R> map(java.util.function.Function<T,R> f) {
        Object[] result = new Object[data.length];
        for (int i=0; i<data.length; i++) result[i] = f.apply((T)data[i]);
        return new ImmutableList<>(result);
    }
    public java.util.Iterator<T> iterator() {
        return new java.util.Iterator<T>() {
            int idx = 0;
            public boolean hasNext() { return idx < data.length; }
            @SuppressWarnings("unchecked")
            public T next() { return (T) data[idx++]; }
        };
    }
    public String toString() { return Arrays.toString(data); }
}

