class NaryTree<T> {
    private T value;
    private final List<NaryTree<T>> children = new ArrayList<>();
    public NaryTree(T value) { this.value = value; }
    public T getValue() { return value; }
    public NaryTree<T> addChild(T childValue) {
        NaryTree<T> child = new NaryTree<>(childValue);
        children.add(child);
        return child;
    }
    public Optional<NaryTree<T>> find(T target) {
        if (Objects.equals(value, target)) return Optional.of(this);
        for (NaryTree<T> child : children) {
            Optional<NaryTree<T>> found = child.find(target);
            if (found.isPresent()) return found;
        }
        return Optional.empty();
    }
    public int depth() {
        if (children.isEmpty()) return 0;
        return 1 + children.stream().mapToInt(NaryTree::depth).max().orElse(0);
    }
    public int size() { return 1 + children.stream().mapToInt(NaryTree::size).sum(); }
    public List<T> toList() {
        List<T> result = new ArrayList<>();
        Queue<NaryTree<T>> queue = new LinkedList<>();
        queue.offer(this);
        while (!queue.isEmpty()) {
            NaryTree<T> node = queue.poll();
            result.add(node.value);
            queue.addAll(node.children);
        }
        return result;
    }
    public <R> NaryTree<R> map(java.util.function.Function<T,R> f) {
        NaryTree<R> mapped = new NaryTree<>(f.apply(value));
        for (NaryTree<T> child : children) mapped.children.add(child.map(f));
        return mapped;
    }
    public <R> R fold(R identity, java.util.function.BiFunction<R,T,R> acc) {
        R result = acc.apply(identity, value);
        for (NaryTree<T> child : children) result = child.fold(result, acc);
        return result;
    }
}

