sealed interface Maybe<T> permits Maybe.Present, Maybe.Empty {
    record Present<T>(T value) implements Maybe<T> {}
    record Empty<T>() implements Maybe<T> {}
    static <T> Maybe<T> of(T value) { return value != null ? new Present<>(value) : new Empty<>(); }
    static <T> Maybe<T> empty() { return new Empty<>(); }
    default <R> Maybe<R> map(java.util.function.Function<T,R> f) {
        return switch(this) {
            case Present<T> p -> Maybe.of(f.apply(p.value()));
            case Empty<T> e   -> Maybe.empty();
        };
    }
    default <R> Maybe<R> flatMap(java.util.function.Function<T,Maybe<R>> f) {
        return switch(this) {
            case Present<T> p -> f.apply(p.value());
            case Empty<T> e   -> Maybe.empty();
        };
    }
    default Maybe<T> filter(java.util.function.Predicate<T> pred) {
        return switch(this) {
            case Present<T> p -> pred.test(p.value()) ? this : Maybe.empty();
            case Empty<T> e   -> this;
        };
    }
    default T orElse(T fallback) {
        return switch(this) {
            case Present<T> p -> p.value();
            case Empty<T> e   -> fallback;
        };
    }
    default T orElseGet(java.util.function.Supplier<T> s) {
        return switch(this) {
            case Present<T> p -> p.value();
            case Empty<T> e   -> s.get();
        };
    }
    default void ifPresent(java.util.function.Consumer<T> action) {
        if (this instanceof Present<T> p) action.accept(p.value());
    }
    default boolean isPresent() { return this instanceof Present; }
    static <T> Maybe<java.util.List<T>> sequence(java.util.List<Maybe<T>> maybes) {
        java.util.List<T> values = new java.util.ArrayList<>();
        for (Maybe<T> m : maybes) {
            if (!m.isPresent()) return Maybe.empty();
            values.add(((Present<T>)m).value());
        }
        return Maybe.of(values);
    }
}

