public final class PersistentMap<K, V> {
    private final List<Map.Entry<K,V>> entries;

    private PersistentMap(List<Map.Entry<K,V>> entries) {
        this.entries = Collections.unmodifiableList(new ArrayList<>(entries));
    }

    public static <K,V> PersistentMap<K,V> empty() {
        return new PersistentMap<>(Collections.emptyList());
    }

    public PersistentMap<K,V> put(K key, V value) {
        List<Map.Entry<K,V>> newEntries = new ArrayList<>();
        boolean replaced = false;
        for (Map.Entry<K,V> e : entries) {
            if (Objects.equals(e.getKey(), key)) {
                newEntries.add(Map.entry(key, value));
                replaced = true;
            } else {
                newEntries.add(e);
            }
        }
        if (!replaced) newEntries.add(Map.entry(key, value));
        return new PersistentMap<>(newEntries);
    }

    public Optional<V> get(K key) {
        return entries.stream()
            .filter(e -> Objects.equals(e.getKey(), key))
            .map(Map.Entry::getValue)
            .findFirst();
    }

    public PersistentMap<K,V> remove(K key) {
        List<Map.Entry<K,V>> newEntries = entries.stream()
            .filter(e -> !Objects.equals(e.getKey(), key))
            .collect(Collectors.toList());
        return new PersistentMap<>(newEntries);
    }

    public boolean containsKey(K key) { return get(key).isPresent(); }
    public int size() { return entries.size(); }
    public Set<K> keys() {
        return entries.stream().map(Map.Entry::getKey).collect(Collectors.toSet());
    }

    public String toString() {
        return entries.stream()
            .map(e -> e.getKey() + "=" + e.getValue())
            .collect(Collectors.joining(", ", "{", "}"));
    }
}
